diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 28d7e1ce401e..9a8c5d8a7b89 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -3019,12 +3019,36 @@ static bool isKnownNonZeroFromOperator(const Operator *I,
     // (X | (X != 0)) is non zero
     if (matchOpWithOpEqZero(I->getOperand(0), I->getOperand(1)))
       return true;
+    // X | Y != 0 if X != Y from dominating condition.
+    // If X | Y == 0, then X == 0 and Y == 0, so X == Y.
+    // Therefore, if X != Y, then X | Y != 0.
+    if (Q.DC && Q.CxtI && Q.DT) {
+      Value *X = I->getOperand(0);
+      Value *Y = I->getOperand(1);
+      auto CheckDominatingCond = [&](Value *A, Value *B) {
+        for (BranchInst *BI : Q.DC->conditionsFor(A)) {
+          Value *Cond = BI->getCondition();
+          // Check if the condition is icmp ne A, B or icmp ne B, A.
+          CmpPredicate Pred;
+          if (match(Cond, m_c_ICmp(Pred, m_Specific(A), m_Specific(B)))) {
+            if (Pred == CmpInst::ICMP_NE) {
+              // Check if the ne branch (successor 0 for icmp ne) dominates.
+              BasicBlockEdge Edge(BI->getParent(), BI->getSuccessor(0));
+              if (Q.DT->dominates(Edge, Q.CxtI->getParent()))
+                return true;
+            }
+          }
+        }
+        return false;
+      };
+      if (CheckDominatingCond(X, Y))
+        return true;
+      if (CheckDominatingCond(Y, X))
+        return true;
+    }
     // X | Y != 0 if X != 0 or Y != 0.
     return isKnownNonZero(I->getOperand(1), DemandedElts, Q, Depth) ||
            isKnownNonZero(I->getOperand(0), DemandedElts, Q, Depth);
-  case Instruction::SExt:
-  case Instruction::ZExt:
-    // ext X != 0 if X != 0.
     return isKnownNonZero(I->getOperand(0), DemandedElts, Q, Depth);

   case Instruction::Shl: {
@@ -10246,6 +10270,10 @@ void llvm::findValuesAffectedByCondition(
             AddAffected(X);
             AddAffected(Y);
           }
+        } else {
+          // icmp eq/ne X, Y can inform X | Y != 0: if X != Y then X | Y != 0.
+          AddAffected(A);
+          AddAffected(B);
         }
